UPDATE public.meditations
SET title = 'Anapanasati',
    duration_minutes = 30,
    description = 'Meditación de atención a la respiración en la tradición Triratna. Consta de cuatro etapas progresivas: (1) Contar al exhalar, de 1 a 10 y volver a empezar, para estabilizar la mente. (2) Contar al inhalar, aumentando la presencia y el enfoque. (3) Seguimiento natural, abandonando el conteo para observar el flujo del aire. (4) Focalización estricta en el punto de contacto del aire con las fosas nasales o el labio superior.'
WHERE id = '2ba650c5-01aa-433e-a42c-55df17723926';